import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5001/api';

// Enhanced debugging
console.log('🔧 Movie Service Config:', {
  API_BASE_URL,
  NODE_ENV: process.env.NODE_ENV,
  REACT_APP_API_URL: process.env.REACT_APP_API_URL
});

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: { 'Content-Type': 'application/json' },
  timeout: 30000, // 30 second timeout
});

// Enhanced request interceptor with debugging
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  console.log('📤 API Request:', {
    method: config.method?.toUpperCase(),
    url: config.url,
    baseURL: config.baseURL,
    fullURL: `${config.baseURL}${config.url}`,
    headers: config.headers,
    params: config.params,
    data: config.data,
    hasToken: !!token
  });

  return config;
});

// Enhanced response interceptor with debugging
api.interceptors.response.use(
  (response) => {
    console.log('📥 API Response Success:', {
      status: response.status,
      url: response.config.url,
      data: response.data,
      headers: response.headers
    });
    return response;
  },
  (error) => {
    console.error('💥 API Response Error:', {
      message: error.message,
      status: error.response?.status,
      statusText: error.response?.statusText,
      url: error.config?.url,
      fullURL: error.config ? `${error.config.baseURL}${error.config.url}` : 'unknown',
      responseData: error.response?.data,
      responseHeaders: error.response?.headers,
      requestHeaders: error.config?.headers,
      timeout: error.code === 'ECONNABORTED' ? 'Request timed out' : null,
      network: error.message === 'Network Error' ? 'Network connection failed' : null
    });

    // Handle token expiration
    if (error.response?.status === 401) {
      console.warn('🔒 Token expired or invalid, redirecting to login');
      localStorage.removeItem('token');
      window.location.href = '/login';
    }

    return Promise.reject(error);
  }
);

// Test API connection
export const testApiConnection = async () => {
  try {
    console.log('🧪 Testing API connection...');
    const response = await api.get('/health'); // Try a health check endpoint
    console.log('✅ API connection successful');
    return { success: true, data: response.data };
  } catch (error) {
    console.error('❌ API connection failed:', error.message);
    return { success: false, error: error.message };
  }
};

// Enhanced getMovieDetails function with extensive debugging
export async function getMovieDetails(movieId) {
  if (!movieId) {
    const error = new Error('Movie ID is required');
    console.error('❌ getMovieDetails: No movieId provided');
    throw error;
  }

  console.log('🎬 getMovieDetails: Starting request for movieId:', movieId);

  try {
    // First test if the API is reachable
    const testConnection = await testApiConnection();
    if (!testConnection.success) {
      console.error('❌ API connection test failed before getMovieDetails');
    }

    const response = await api.get(`/movies/${movieId}`);

    console.log('✅ getMovieDetails: Success response:', {
      status: response.status,
      dataType: typeof response.data,
      hasData: !!response.data,
      dataKeys: response.data ? Object.keys(response.data) : [],
      movieId: response.data?.id,
      movieTitle: response.data?.title
    });

    if (!response.data) {
      throw new Error('No data returned from server');
    }

    return response.data;
  } catch (error) {
    console.error('💥 getMovieDetails: Error details:', {
      movieId,
      errorType: error.constructor.name,
      message: error.message,
      status: error.response?.status,
      statusText: error.response?.statusText,
      responseData: error.response?.data,
      isNetworkError: error.message === 'Network Error',
      isTimeoutError: error.code === 'ECONNABORTED',
      stack: error.stack
    });

    // Re-throw with enhanced error information
    const enhancedError = new Error(error.message);
    enhancedError.response = error.response;
    enhancedError.originalError = error;
    enhancedError.movieId = movieId;
    throw enhancedError;
  }
}

// Get movies with pagination and filters
export async function getMovies(page = 1, limit = 20, genre = null, sortBy = 'avg_rating') {
  const params = { page, limit, sort_by: sortBy };
  if (genre) params.genre = genre;

  console.log('🎬 getMovies: Request params:', params);

  try {
    const response = await api.get('/movies/', { params });
    console.log('✅ getMovies: Success, received', response.data?.movies?.length || 0, 'movies');
    return response.data;
  } catch (error) {
    console.error('💥 getMovies: Error:', error.message);
    throw error;
  }
}

// Search movies
export async function searchMovies(query, limit = 20) {
  console.log('🔍 searchMovies: Query:', query, 'Limit:', limit);

  try {
    const response = await api.get('/movies/search', { params: { q: query, limit } });
    console.log('✅ searchMovies: Success, found', response.data?.movies?.length || 0, 'movies');
    return response.data;
  } catch (error) {
    console.error('💥 searchMovies: Error:', error.message);
    throw error;
  }
}

// Get movie genres
export async function getGenres() {
  console.log('🎭 getGenres: Starting request...');

  try {
    const response = await api.get('/movies/genres');
    console.log('✅ getGenres: Success, received genres:', response.data);
    return response.data;
  } catch (error) {
    console.error('💥 getGenres: Error:', error.message);
    throw error;
  }
}

// Get popular movies
export async function getPopularMovies(genre = null, limit = 20) {
  const params = { limit };
  if (genre) params.genre = genre;

  console.log('🔥 getPopularMovies: Request params:', params);

  try {
    const response = await api.get('/movies/popular', { params });
    console.log('✅ getPopularMovies: Success');
    return response.data;
  } catch (error) {
    console.error('💥 getPopularMovies: Error:', error.message);
    throw error;
  }
}

// Debug function to manually test API endpoints
export const debugApiEndpoints = async () => {
  console.log('🧪 Starting API endpoints debug test...');

  const endpoints = [
    { name: 'Health Check', url: '/health' },
    { name: 'Movies List', url: '/movies/' },
    { name: 'Movie Genres', url: '/movies/genres' },
    { name: 'Movie Details (ID: 1)', url: '/movies/1' },
    { name: 'Popular Movies', url: '/movies/popular' }
  ];

  const results = [];

  for (const endpoint of endpoints) {
    try {
      console.log(`🧪 Testing ${endpoint.name}: ${endpoint.url}`);
      const response = await api.get(endpoint.url);
      results.push({
        ...endpoint,
        success: true,
        status: response.status,
        dataType: typeof response.data,
        hasData: !!response.data
      });
      console.log(`✅ ${endpoint.name}: SUCCESS`);
    } catch (error) {
      results.push({
        ...endpoint,
        success: false,
        status: error.response?.status,
        error: error.message,
        responseData: error.response?.data
      });
      console.error(`❌ ${endpoint.name}: FAILED -`, error.message);
    }
  }

  console.log('🧪 Debug test complete. Results:', results);
  return results;
};

export default {
  getMovies,
  searchMovies,
  getMovieDetails,
  getGenres,
  getPopularMovies,
  testApiConnection,
  debugApiEndpoints
};
